import React, { useState, useEffect } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, SafeAreaView, ActivityIndicator, Alert } from 'react-native';
import * as Location from 'expo-location';
import axios from 'axios';
import MapView, { Marker, Polyline } from './src/MapView';
import { API_BASE_URL } from './src/constants';

const VALENCIA_PLACES: Record<string, { lat: number; lon: number }> = {
  'plaza ayuntamiento': { lat: 39.4699, lon: -0.3763 },
  'ciudad de las ciencias': { lat: 39.4544, lon: -0.3507 },
  'estacion del norte': { lat: 39.4668, lon: -0.3774 },
  'jardin del turia': { lat: 39.4730, lon: -0.3700 },
  'playa malvarrosa': { lat: 39.4794, lon: -0.3233 },
  'bioparc': { lat: 39.4797, lon: -0.4057 },
  'mestalla': { lat: 39.4746, lon: -0.3584 },
};

type TransportMode = 'walking' | 'bicycle' | 'scooter' | 'skateboard';

const TRANSPORT_ICONS: Record<TransportMode, string> = {
  walking: '🚶', bicycle: '🚲', scooter: '🛴', skateboard: '🛹',
};

const TRANSPORT_LABELS: Record<TransportMode, string> = {
  walking: 'Andando', bicycle: 'Bicicleta', scooter: 'Patinete', skateboard: 'Monopatín',
};

export default function App() {
  const [userLocation, setUserLocation] = useState<any>(null);
  const [origin, setOrigin] = useState<any>(null);
  const [destination, setDestination] = useState<any>(null);
  const [transportMode, setTransportMode] = useState<TransportMode>('bicycle');
  const [preference, setPreference] = useState<'eco_fast' | 'leisure'>('eco_fast');
  const [route, setRoute] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectingOrigin, setSelectingOrigin] = useState(true);
  const [showResults, setShowResults] = useState(false);

  useEffect(() => { getLocation(); }, []);

  const getLocation = async () => {
    const { status } = await Location.requestForegroundPermissionsAsync();
    if (status !== 'granted') return;
    const loc = await Location.getCurrentPositionAsync({});
    const coords = { latitude: loc.coords.latitude, longitude: loc.coords.longitude };
    setUserLocation(coords);
    setOrigin(coords);
  };

  const handleMapPress = (e: any) => {
    const coord = e.nativeEvent.coordinate;
    if (selectingOrigin) { setOrigin(coord); setSelectingOrigin(false); }
    else { setDestination(coord); }
  };

  const searchPlace = (name: string) => {
    const coords = VALENCIA_PLACES[name.toLowerCase()];
    if (!coords) return Alert.alert('No encontrado', 'Prueba: plaza ayuntamiento, ciudad de las ciencias...');
    if (selectingOrigin) { setOrigin(coords); setSelectingOrigin(false); }
    else { setDestination(coords); }
  };

  const calculateRoute = async () => {
    if (!origin || !destination) return;
    setLoading(true); setError(null);
    try {
      const res = await axios.post(API_BASE_URL + '/api/v1/routes', {
        origin: { lat: origin.latitude, lon: origin.longitude },
        destination: { lat: destination.latitude, lon: destination.longitude },
        transport_mode: transportMode, preference,
      });
      if (res.data?.[0]) { setRoute(res.data[0]); setShowResults(true); }
    } catch (e: any) {
      setError(e.message);
    } finally { setLoading(false); }
  };

  const reset = () => {
    setRoute(null); setShowResults(false);
    setOrigin(userLocation); setDestination(null);
    setSelectingOrigin(true); setError(null);
  };

  return (
    <SafeAreaView style={styles.container}>
      <MapView
        style={styles.map}
        region={{ latitude: 39.4699, longitude: -0.3763, latitudeDelta: 0.05, longitudeDelta: 0.05 }}
        onPress={handleMapPress}
      />

      <View style={styles.topBar}>
        <Text style={styles.searchLabel}>{selectingOrigin ? '🟢 Selecciona ORIGEN' : '🔴 Selecciona DESTINO'}</Text>
        <View style={styles.searchRow}>
          <TouchableOpacity style={styles.searchBtn} onPress={() => {
            const name = prompt('Buscar lugar (ej: plaza ayuntamiento):');
            if (name) searchPlace(name);
          }}>
            <Text style={{ color: '#666' }}>🔍 Buscar lugar...</Text>
          </TouchableOpacity>
          <TouchableOpacity style={styles.locateBtn} onPress={getLocation}>
            <Text style={{ fontSize: 20 }}>📍</Text>
          </TouchableOpacity>
        </View>
      </View>

      <View style={styles.transportPanel}>
        {(['walking', 'bicycle', 'scooter', 'skateboard'] as TransportMode[]).map(m => (
          <TouchableOpacity key={m} style={[styles.tBtn, transportMode === m && styles.tBtnActive]} onPress={() => setTransportMode(m)}>
            <Text style={{ fontSize: 24 }}>{TRANSPORT_ICONS[m]}</Text>
            {transportMode === m && <Text style={{ color: '#fff', fontSize: 10, marginLeft: 4 }}>{TRANSPORT_LABELS[m]}</Text>}
          </TouchableOpacity>
        ))}
      </View>

      <View style={styles.prefPanel}>
        <TouchableOpacity style={[styles.pBtn, preference === 'eco_fast' && styles.pBtnActive]} onPress={() => setPreference('eco_fast')}>
          <Text style={{ fontSize: 20 }}>⚡</Text>
          <Text style={[styles.pLabel, preference === 'eco_fast' && { color: '#fff' }]}>ECO</Text>
        </TouchableOpacity>
        <TouchableOpacity style={[styles.pBtn, preference === 'leisure' && styles.pBtnActive]} onPress={() => setPreference('leisure')}>
          <Text style={{ fontSize: 20 }}>🌸</Text>
          <Text style={[styles.pLabel, preference === 'leisure' && { color: '#fff' }]}>Paseo</Text>
        </TouchableOpacity>
      </View>

      {!showResults && (
        <TouchableOpacity style={styles.calcBtn} onPress={calculateRoute} disabled={!origin || !destination || loading}>
          {loading ? <ActivityIndicator color="#fff" /> : <Text style={{ color: '#fff', fontSize: 18, fontWeight: 'bold' }}>🚀 Calcular Ruta Eco</Text>}
        </TouchableOpacity>
      )}

      {showResults && route && (
        <View style={styles.results}>
          <TouchableOpacity style={{ position: 'absolute', top: 10, right: 15, backgroundColor: '#e74c3c', width: 30, height: 30, borderRadius: 15, justifyContent: 'center', alignItems: 'center' }} onPress={reset}><Text style={{ color: '#fff' }}>✕</Text></TouchableOpacity>
          <Text style={{ fontSize: 20, fontWeight: 'bold', textAlign: 'center', marginBottom: 12 }}>{TRANSPORT_ICONS[transportMode]} {TRANSPORT_LABELS[transportMode]}</Text>
          <View style={{ flexDirection: 'row', flexWrap: 'wrap', justifyContent: 'space-around' }}>
            {[
              ['📏', route.total_distance_km + ' km', 'Distancia'],
              ['⏱️', route.total_duration_min + ' min', 'Duración'],
              ['🌍', route.co2_saved_kg + ' kg', 'CO₂ ahorrado'],
              ['💨', route.avg_air_quality_index + '/5', 'Calidad aire'],
              ['🌳', (route.green_percentage * 100).toFixed(0) + '%', 'Zonas verdes'],
            ].map(([icon, val, desc], i) => (
              <View key={i} style={{ width: '30%', alignItems: 'center', backgroundColor: '#f8f9fa', padding: 10, borderRadius: 12, marginBottom: 8 }}>
                <Text style={{ fontSize: 24 }}>{icon}</Text>
                <Text style={{ fontSize: 16, fontWeight: 'bold', color: '#333' }}>{val}</Text>
                <Text style={{ fontSize: 10, color: '#666' }}>{desc}</Text>
              </View>
            ))}
          </View>
          <TouchableOpacity style={{ backgroundColor: '#3498db', padding: 12, borderRadius: 25, alignItems: 'center', marginTop: 10 }} onPress={reset}>
            <Text style={{ color: '#fff', fontWeight: 'bold' }}>🔄 Nueva Ruta</Text>
          </TouchableOpacity>
        </View>
      )}

      {error && (
        <View style={{ position: 'absolute', bottom: 30, left: 20, right: 20, backgroundColor: '#e74c3c', padding: 15, borderRadius: 15 }}>
          <Text style={{ color: '#fff' }}>❌ {error}</Text>
        </View>
      )}
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  map: { width: '100%', height: '100%' },
  topBar: { position: 'absolute', top: 10, left: 10, right: 10, backgroundColor: 'rgba(255,255,255,0.95)', borderRadius: 15, padding: 12, elevation: 5 },
  searchLabel: { fontSize: 16, fontWeight: '600', marginBottom: 8 },
  searchRow: { flexDirection: 'row', gap: 8 },
  searchBtn: { flex: 1, backgroundColor: '#f0f0f0', borderRadius: 20, padding: 10, paddingHorizontal: 15 },
  locateBtn: { backgroundColor: '#2ecc71', width: 40, height: 40, borderRadius: 20, justifyContent: 'center', alignItems: 'center' },
